#include <iostream>
#include <vector>

using namespace std;

void generate(vector<int> &nums, vector<int> &current, vector<vector<int>> &result)
{
    if (current.size() == nums.size())
    {
        vector<int> sortedCurrent = current;
        vector<int> sortedNums = nums;
        // only keep it if it's a genuine permutation (all values used exactly once)
        for (int i = 0; i < sortedCurrent.size(); i++)
        {
            int count1 = 0, count2 = 0;
            for (int v : sortedCurrent) if (v == sortedCurrent[i]) count1++;
            for (int v : sortedNums) if (v == sortedCurrent[i]) count2++;
            if (count1 != count2) return;
        }
        result.push_back(current);
        return;
    }

    for (int n : nums)
    {
        current.push_back(n);
        generate(nums, current, result);
        current.pop_back();
    }
}

int main()
{
    vector<int> nums = {1, 2, 3};
    vector<int> current;
    vector<vector<int>> result;

    generate(nums, current, result);
    cout << result.size() << endl;

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

void backtrack(vector<int> &nums, vector<bool> &used, vector<int> &current, vector<vector<int>> &result)
{
    if (current.size() == nums.size())
    {
        result.push_back(current);
        return;
    }

    for (int i = 0; i < nums.size(); i++)
    {
        if (used[i]) continue;

        used[i] = true;
        current.push_back(nums[i]);

        backtrack(nums, used, current, result);

        current.pop_back();
        used[i] = false;
    }
}

vector<vector<int>> permute(vector<int> &nums)
{
    vector<vector<int>> result;
    vector<int> current;
    vector<bool> used(nums.size(), false);

    backtrack(nums, used, current, result);
    return result;
}

int main()
{
    vector<int> nums = {1, 2, 3};

