using namespace std;

void backtrack(vector<int> &candidates, int target, int start, vector<int> &current, vector<vector<int>> &result)
{
    int sum = 0;
    for (int c : current) sum += c;

    if (sum == target)
    {
        result.push_back(current);
        return;
    }
    if (sum > target || start == candidates.size()) return;

    current.push_back(candidates[start]);
    backtrack(candidates, target, start, current, result); // reuse same index
    current.pop_back();

    backtrack(candidates, target, start + 1, current, result); // move on
}

int main()
{
    vector<int> candidates = {2, 3, 6, 7};
    vector<int> current;
    vector<vector<int>> result;

    backtrack(candidates, 7, 0, current, result);
    cout << result.size() << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

void backtrack(vector<int> &candidates, int remaining, int start, vector<int> &current, vector<vector<int>> &result)
{
    if (remaining == 0)
    {
        result.push_back(current);
        return;
    }

    for (int i = start; i < candidates.size(); i++)
    {
        if (candidates[i] > remaining) break; // sorted, so nothing further can work either

        current.push_back(candidates[i]);
        backtrack(candidates, remaining - candidates[i], i, current, result); // reuse index i
        current.pop_back();
    }
}

vector<vector<int>> combinationSum(vector<int> &candidates, int target)
{
    sort(candidates.begin(), candidates.end());
    vector<vector<int>> result;
    vector<int> current;
    backtrack(candidates, target, 0, current, result);
    return result;
}

int main()
{
    vector<int> candidates = {2, 3, 6, 7};

    auto result = combinationSum(candidates, 7);
    cout << result.size() << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <unordered_map>

using namespace std;

vector<string> letterCombinations(string digits)
{
    if (digits.empty()) return {};

    unordered_map<char, string> keypad = {
        {'2',"abc"}, {'3',"def"}, {'4',"ghi"}, {'5',"jkl"},
        {'6',"mno"}, {'7',"pqrs"}, {'8',"tuv"}, {'9',"wxyz"}
    };

    vector<string> result = {""};

    for (char d : digits)
    {
        vector<string> next;
        for (string &prefix : result)
        {
            for (char c : keypad[d])
            {
                next.push_back(prefix + c);
            }
        }
        result = next;
    }

    return result;
}

int main()
{
    auto result = letterCombinations("23");
    cout << result.size() << endl;

    return 0;
}

